import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';
import GDRoom from '../components/GDRoom';
import { gdAPI } from '../services/api';

/* ── Room card ─────────────────────────────────────────────── */
function RoomCard({ room, onJoin }) {
    return (
        <div className="glass-card p-5 hover:scale-[1.02] transition-transform duration-200">
            <div className="flex items-start justify-between gap-3 mb-3">
                <div>
                    <h4 className="text-white font-semibold text-sm">{room.name}</h4>
                    <p className="text-white/40 text-xs mt-0.5 line-clamp-2">{room.topic}</p>
                </div>
                <span className={`badge border flex-shrink-0 ${room.participants < room.maxParticipants
                        ? 'bg-neon-green/20 text-neon-green border-neon-green/30'
                        : 'bg-red-500/20 text-red-400 border-red-500/30'
                    }`}>
                    {room.participants}/{room.maxParticipants}
                </span>
            </div>

            <div className="flex items-center gap-3 text-xs text-white/40 mb-4">
                <span>👥 {room.participants} online</span>
                <span>·</span>
                <span>⏱ {room.duration || 30} min</span>
                <span>·</span>
                <span className="capitalize">{room.level || 'All levels'}</span>
            </div>

            <button
                onClick={() => onJoin(room)}
                disabled={room.participants >= room.maxParticipants}
                className="btn-primary w-full text-center justify-center disabled:opacity-40 disabled:cursor-not-allowed"
            >
                {room.participants >= room.maxParticipants ? 'Room Full' : 'Join Room →'}
            </button>
        </div>
    );
}

/* ── Create room modal ─────────────────────────────────────── */
function CreateRoomModal({ onClose, onCreate }) {
    const [form, setForm] = useState({ name: '', topic: '' });
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!form.name || !form.topic) return;
        setLoading(true);
        await onCreate(form.name, form.topic);
        setLoading(false);
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="glass-card w-full max-w-sm p-6 animate-fadeInUp">
                <h3 className="section-title mb-4">Create a Room</h3>
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="label-text">Room Name</label>
                        <input
                            className="input-field" placeholder="e.g. Tech Trends Discussion"
                            value={form.name}
                            onChange={e => setForm(p => ({ ...p, name: e.target.value }))}
                            required
                        />
                    </div>
                    <div>
                        <label className="label-text">Discussion Topic</label>
                        <input
                            className="input-field" placeholder="e.g. AI impact on jobs in 2025"
                            value={form.topic}
                            onChange={e => setForm(p => ({ ...p, topic: e.target.value }))}
                            required
                        />
                    </div>
                    <div className="flex gap-3 pt-2">
                        <button type="button" onClick={onClose} className="btn-secondary flex-1">Cancel</button>
                        <button type="submit" disabled={loading} className="btn-primary flex-1">
                            {loading ? 'Creating…' : 'Create'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

const DEMO_ROOMS = [
    { id: 'room-1', name: 'AI & Future of Work', topic: 'Discuss how AI is reshaping industries and career paths.', participants: 4, maxParticipants: 8, duration: 30, level: 'All levels' },
    { id: 'room-2', name: 'Campus Placement Prep', topic: 'Share tips and experiences from campus recruitment drives.', participants: 6, maxParticipants: 8, duration: 45, level: 'Beginners' },
    { id: 'room-3', name: 'Climate Change Debate', topic: 'Should developing nations prioritize economic growth over climate action?', participants: 3, maxParticipants: 6, duration: 20, level: 'Advanced' },
    { id: 'room-4', name: 'Startup Culture', topic: 'Is startup culture overrated? Pros and cons of working in startups.', participants: 8, maxParticipants: 8, duration: 30, level: 'All levels' },
];

export default function GroupDiscussion() {
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [rooms, setRooms] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeRoom, setActiveRoom] = useState(null);
    const [showCreate, setShowCreate] = useState(false);

    useEffect(() => {
        gdAPI.getRooms()
            .then(res => setRooms(res.data?.rooms || DEMO_ROOMS))
            .catch(() => setRooms(DEMO_ROOMS))
            .finally(() => setLoading(false));
    }, []);

    const handleJoin = async (room) => {
        try {
            await gdAPI.joinRoom(room.id);
        } catch { /* join anyway for demo */ }
        setActiveRoom(room);
    };

    const handleLeave = () => {
        setActiveRoom(null);
        // Refresh rooms
        gdAPI.getRooms()
            .then(res => setRooms(res.data?.rooms || DEMO_ROOMS))
            .catch(() => { });
    };

    const handleCreate = async (name, topic) => {
        try {
            const res = await gdAPI.createRoom(name, topic);
            const newRoom = res.data?.room || {
                id: `room-${Date.now()}`, name, topic, participants: 1, maxParticipants: 8, duration: 30,
            };
            setRooms(p => [newRoom, ...p]);
            setActiveRoom(newRoom);
        } catch {
            const newRoom = { id: `room-${Date.now()}`, name, topic, participants: 1, maxParticipants: 8, duration: 30 };
            setRooms(p => [newRoom, ...p]);
            setActiveRoom(newRoom);
        }
    };

    return (
        <div className="min-h-screen bg-dark-900 flex">
            <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} />

            <div className="flex-1 flex flex-col min-w-0">
                <Navbar onMenuClick={() => setSidebarOpen(true)} />

                <main className="flex-1 p-4 md:p-6 space-y-6 overflow-y-auto">
                    {/* Header */}
                    <div className="flex items-center justify-between">
                        <div>
                            <h2 className="section-title text-2xl">Group Discussion</h2>
                            <p className="section-subtitle">Join live rooms and practice structured debate.</p>
                        </div>
                        {!activeRoom && (
                            <button onClick={() => setShowCreate(true)} className="btn-primary flex items-center gap-2">
                                <span>+</span> New Room
                            </button>
                        )}
                    </div>

                    {activeRoom ? (
                        /* Active room view */
                        <div className="animate-fadeIn">
                            <div className="flex items-center gap-2 mb-4">
                                <button onClick={handleLeave} className="text-white/40 hover:text-white text-sm flex items-center gap-1 transition-colors">
                                    ← Back to Rooms
                                </button>
                            </div>
                            <GDRoom
                                roomId={activeRoom.id}
                                roomName={activeRoom.name}
                                topic={activeRoom.topic}
                                onLeave={handleLeave}
                            />
                        </div>
                    ) : (
                        /* Room list */
                        <>
                            {/* How it works */}
                            <div className="glass-card p-5">
                                <h3 className="text-white font-semibold text-sm mb-3">📋 How it works</h3>
                                <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                                    {[
                                        { step: '01', title: 'Join or create a room', desc: 'Pick a topic that interests you or start your own.' },
                                        { step: '02', title: 'Discuss in real-time', desc: 'Chat with other participants via WebSocket messaging.' },
                                        { step: '03', title: 'Get evaluated', desc: 'AI analyses your communication and gives feedback.' },
                                    ].map(s => (
                                        <div key={s.step} className="flex gap-3">
                                            <span className="text-primary-400 font-bold text-lg flex-shrink-0">{s.step}</span>
                                            <div>
                                                <p className="text-white text-xs font-semibold">{s.title}</p>
                                                <p className="text-white/40 text-xs mt-0.5">{s.desc}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* Rooms grid */}
                            {loading ? (
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                                    {[1, 2, 3].map(i => (
                                        <div key={i} className="glass-card p-5 h-48 animate-pulse" />
                                    ))}
                                </div>
                            ) : (
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                                    {rooms.map(room => (
                                        <RoomCard key={room.id} room={room} onJoin={handleJoin} />
                                    ))}
                                </div>
                            )}
                        </>
                    )}
                </main>
            </div>

            {showCreate && (
                <CreateRoomModal onClose={() => setShowCreate(false)} onCreate={handleCreate} />
            )}
        </div>
    );
}
